DELETE FROM cotdl.tbl_piiordersteptableupdate
WHERE orderid IN (
	SELECT orderid FROM cotdl.tbl_piiorder
	WHERE jobtype != 'PII'
	  AND jobid NOT LIKE 'ARC_DATA_DELETE%'
	  AND jobid NOT LIKE 'RESTORE_CUSTID%'
	  AND status IN ('Ended OK', 'Recovered')
	  AND realendtime <= #{cutoffDate}
);
