update cotdl.tbl_piiorder
   set 
		status= #{status, jdbcType=VARCHAR}
where orderid= #{orderid}

mapper.select:
 
		 
		select * from (
			select orderid,  DATE_FORMAT(basedate,'%Y/%m/%d') as basedate, runcnt, jobid, version, jobname,system, policy_id, keymap_id, jobtype, runtype, calendar, time, status, confirmflag, holdflag, forceokflag, killflag,  DATE_FORMAT(eststarttime,'%Y/%m/%d %H:%i:%s') as eststarttime, runningtime,  DATE_FORMAT(realstarttime,'%Y/%m/%d %H:%i:%s') as realstarttime,  DATE_FORMAT(realendtime,'%Y/%m/%d %H:%i:%s') as realendtime, job_owner_id1, job_owner_name1, job_owner_id2, job_owner_name2, job_owner_id3, job_owner_name3,  DATE_FORMAT(orderdate,'%Y/%m/%d %H:%i:%s') as orderdate, orderuserid
			  from cotdl.tbl_piiorder
			
			
			
			limit #{offset}, #{amount}
			
		) a
		order by orderid desc

select orderid, basedate, runcnt, jobid, version, jobname,system, policy_id, keymap_id, jobtype, runtype, calendar, time, status, confirmflag, holdflag, forceokflag, killflag, eststarttime, runningtime, realstarttime, realendtime, job_owner_id1, job_owner_name1, job_owner_id2, job_owner_name2, job_owner_id3, job_owner_name3, orderdate, orderuserid , (select group_concat(orderid SEPARATOR ',') from cotdl.tbl_piiorder where jobid=d.jobid and status in ('Ended not OK', 'Running', 'Hold') and orderid!=d.orderid) as waitreason_samejobnotcompleted , (case when eststarttime_org > NOW() then eststarttime else '' end) as waitreason_executiontime , (case when (select count(distinct jobid_w) from cotdl.tbl_piiorderjobwait b where d.orderid = b.orderid and type='PRE') != (select count(1) from cotdl.tbl_piiorder c where c.jobid in (select jobid_w from cotdl.tbl_piiorderjobwait b where d.orderid = b.orderid and type='PRE') and c.basedate = d.basedate and c.status = 'Ended OK' ) then (select group_concat(distinct jobid_w SEPARATOR ',') as jobid from cotdl.tbl_piiorderjobwait b where d.orderid = b.orderid and type='PRE' and jobid_w not in ( select distinct c.jobid as jobid from cotdl.tbl_piiorder c where c.jobid in (select jobid_w from cotdl.tbl_piiorderjobwait b where d.orderid = b.orderid and type='PRE') and c.basedate = d.basedate and c.status = 'Ended OK' ) ) else null end ) as waitreason_waitjob from ( select orderid, DATE_FORMAT(basedate,'%Y/%m/%d') as basedate, runcnt, jobid, version, jobname,system, policy_id, keymap_id, jobtype, runtype, calendar, time, status, confirmflag, holdflag, forceokflag, killflag, DATE_FORMAT(eststarttime,'%Y/%m/%d %H:%i:%s') as eststarttime, eststarttime as eststarttime_org, runningtime, DATE_FORMAT(realstarttime,'%Y/%m/%d %H:%i:%s') as realstarttime, DATE_FORMAT(realendtime,'%Y/%m/%d %H:%i:%s') as realendtime, job_owner_id1, job_owner_name1, job_owner_id2, job_owner_name2, job_owner_id3, job_owner_name3, DATE_FORMAT(orderdate,'%Y/%m/%d %H:%i:%s') as orderdate, orderuserid from cotdl.tbl_piiorder
limit #{offset}, #{amount}
) as d order by orderid desc

